"use client";

import { cn } from "@workspace/ui/lib/utils";

import type {
  CanvasNodeStatus as CanvasNodeStatusData,
  CanvasNodeVisualStatusTone,
} from "./canvas-node.types";

interface StatusVisual {
  breathing: boolean;
  dotClassName: string;
  pillClassName: string;
  textClassName: string;
}

const GREEN: StatusVisual = {
  breathing: true,
  dotClassName: "bg-green-500",
  pillClassName: "bg-green-500/30 text-zinc-50",
  textClassName: "text-green-500",
};
const BLUE: StatusVisual = {
  breathing: true,
  dotClassName: "bg-blue-500",
  pillClassName: "bg-blue-500/30 text-zinc-50",
  textClassName: "text-blue-500",
};
const YELLOW: StatusVisual = {
  breathing: true,
  dotClassName: "bg-yellow-500",
  pillClassName: "bg-yellow-500/30 text-zinc-50",
  textClassName: "text-yellow-500",
};
const GRAY_STATIC: StatusVisual = {
  breathing: false,
  dotClassName: "bg-neutral-500",
  pillClassName: "bg-neutral-500/30 text-zinc-50",
  textClassName: "text-neutral-400",
};
const RED: StatusVisual = {
  breathing: true,
  dotClassName: "bg-red-500",
  pillClassName: "bg-red-500/30 text-zinc-50",
  textClassName: "text-red-500",
};

export const DEFAULT_CANVAS_NODE_STATUS = {
  label: "Unknown",
  visualTone: "neutral",
} as const satisfies CanvasNodeStatusData;

export function normalizeCanvasNodeVisualTone(
  input: string | undefined
): CanvasNodeVisualStatusTone {
  const normalized = input
    ?.trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-");

  switch (normalized) {
    case "positive":
      return normalized;
    case "progress":
      return normalized;
    case "warning":
      return normalized;
    case "negative":
      return normalized;
    case "neutral":
      return normalized;
    default:
      return "neutral";
  }
}

export function resolveCanvasNodeStatus(
  status: CanvasNodeStatusData | undefined
): Required<CanvasNodeStatusData> {
  return {
    label: status?.label?.trim() || DEFAULT_CANVAS_NODE_STATUS.label,
    visualTone: normalizeCanvasNodeVisualTone(status?.visualTone),
  };
}

function getStatusVisual(tone: CanvasNodeVisualStatusTone): StatusVisual {
  switch (tone) {
    case "positive":
      return GREEN;
    case "progress":
      return BLUE;
    case "warning":
      return YELLOW;
    case "negative":
      return RED;
    case "neutral":
      return GRAY_STATIC;
    default:
      return GRAY_STATIC;
  }
}

export function getCanvasNodeStatusTextClassName(
  status: CanvasNodeStatusData | undefined
) {
  const resolvedStatus = resolveCanvasNodeStatus(status);
  return getStatusVisual(resolvedStatus.visualTone).textClassName;
}

export function CanvasNodeStatusDot({
  className,
  size = "default",
  status,
}: {
  className?: string;
  size?: "collapsed" | "default" | "small";
  status?: CanvasNodeStatusData;
}) {
  const resolvedStatus = resolveCanvasNodeStatus(status);
  const visual = getStatusVisual(resolvedStatus.visualTone);
  const dotSize = size === "default" ? "size-3" : "size-2";
  const pingSize = size === "default" ? "size-2.5" : "size-2";

  return (
    <span
      aria-hidden
      className={cn(
        "relative flex shrink-0 items-center justify-center rounded-full",
        size === "default" ? "size-4" : "size-3.5",
        className
      )}
    >
      {visual.breathing ? (
        <span
          className={cn(
            "absolute animate-ping rounded-full opacity-75",
            pingSize,
            visual.dotClassName
          )}
        />
      ) : null}
      <span
        className={cn("relative rounded-full", dotSize, visual.dotClassName)}
      />
    </span>
  );
}

export function CanvasNodeStatusPill({
  className,
  status,
}: {
  className?: string;
  status?: CanvasNodeStatusData;
}) {
  const resolvedStatus = resolveCanvasNodeStatus(status);
  const visual = getStatusVisual(resolvedStatus.visualTone);

  return (
    <span
      className={cn(
        "flex h-5 shrink-0 items-center gap-2.5 rounded-full py-0.5 pr-1 pl-2.5 font-normal text-xs leading-none",
        visual.pillClassName,
        className
      )}
    >
      <span className="truncate">{resolvedStatus.label}</span>
      <CanvasNodeStatusDot size="small" status={status} />
    </span>
  );
}

export function CanvasNodeStatus({
  className,
  status,
}: {
  className?: string;
  status?: CanvasNodeStatusData;
}) {
  return (
    <span
      className={cn(
        "canvas-node-status flex size-8 shrink-0 items-center justify-center",
        className
      )}
    >
      <CanvasNodeStatusDot
        className="canvas-node-status-dot"
        size="collapsed"
        status={status}
      />
    </span>
  );
}

"use client";

import { Button } from "@workspace/ui/components/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@workspace/ui/components/dropdown-menu";
import { Spinner } from "@workspace/ui/components/spinner";
import { cn } from "@workspace/ui/lib/utils";
import { Ellipsis } from "lucide-react";
import type { ComponentProps, ReactNode, SyntheticEvent } from "react";

const RF_CONTROL_CLASS = "nodrag nopan";
const CANVAS_NODE_MENU_ALIGN_OFFSET = -10;
const CANVAS_NODE_MENU_SIDE_OFFSET = 14;

export type CanvasNodeActionTone =
  | "default"
  | "destructive"
  | "info"
  | "muted"
  | "success";

export interface CanvasNodeAction {
  disabled?: boolean;
  loading?: boolean;
  onClick?: () => Promise<void> | void;
}

export function stopCanvasNodeControlEvent(event: SyntheticEvent) {
  event.stopPropagation();
}

export function invokeCanvasNodeAction(action: CanvasNodeAction | undefined) {
  if (!action?.onClick || action.disabled || action.loading) {
    return;
  }

  Promise.resolve(action.onClick()).catch(() => undefined);
}

export function CanvasNodeActionBar({
  className,
  ...props
}: ComponentProps<"div">) {
  return (
    <div
      className={cn(
        "canvas-node-action-bar mt-2 flex min-w-0 items-center justify-end gap-1",
        className
      )}
      data-slot="canvas-node-action-bar"
      {...props}
    />
  );
}

export interface CanvasNodeActionButtonProps {
  action?: CanvasNodeAction;
  "aria-label": string;
  children?: ReactNode;
  className?: string;
  title?: string;
}

export function CanvasNodeActionButton({
  action,
  "aria-label": ariaLabel,
  children,
  className,
  title,
}: CanvasNodeActionButtonProps) {
  const disabled = action?.disabled || action?.loading || !action?.onClick;

  return (
    <Button
      aria-label={ariaLabel}
      className={cn(
        RF_CONTROL_CLASS,
        "canvas-node-action-button flex size-8 shrink-0 cursor-pointer items-center justify-center rounded-lg border-0 bg-zinc-950/20 p-0 text-zinc-50 shadow-none transition-colors hover:text-zinc-50",
        className
      )}
      disabled={disabled}
      onClick={(event) => {
        event.stopPropagation();
        invokeCanvasNodeAction(action);
      }}
      onDoubleClick={stopCanvasNodeControlEvent}
      onKeyDown={stopCanvasNodeControlEvent}
      onPointerDown={stopCanvasNodeControlEvent}
      size={null}
      title={title ?? ariaLabel}
      type="button"
      variant={null}
    >
      {action?.loading ? <Spinner className="size-4" /> : children}
    </Button>
  );
}

export interface CanvasNodeActionMenuProps {
  "aria-label": string;
  children?: ReactNode;
  className?: string;
  contentClassName?: string;
}

export function CanvasNodeActionMenu({
  "aria-label": ariaLabel,
  children,
  className,
  contentClassName,
}: CanvasNodeActionMenuProps) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        render={
          <Button
            aria-label={ariaLabel}
            className={cn(
              RF_CONTROL_CLASS,
