      className={cn(
        "flex h-5 min-w-0 shrink-0 items-center gap-1.5 rounded-full",
        className
      )}
    >
      <CanvasNodeStatusDot size="small" status={resolvedStatus} />
      <span
        className={cn("truncate", getCanvasNodeStatusTextClassName(status))}
      >
        {resolvedStatus.label}
      </span>
    </span>
  );
}

